mapper.delete:
DELETE FROM supply_item
WHERE id = #{id}
  AND deleted = 1

DELETE FROM supply_item WHERE deleted = 1
AND id IN
#{id}

mapper.select:
SELECT * FROM supply_item WHERE shelf_status = 'ON_SHELF' AND deleted = 0
AND category_id = #{categoryId}
ORDER BY id ASC

mapper.update:
UPDATE supply_item
SET stock_qty = stock_qty - #{qty}
WHERE id = #{id}
  AND stock_mode = 'QUANTIFIED'
  AND stock_qty >= #{qty}

UPDATE supply_item
SET last_inbound_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT DISTINCT i.id FROM supply_item i WHERE i.deleted = 0
AND i.category_id = #{categoryId}
AND ( EXISTS (SELECT 1 FROM supply_inventory_movement m WHERE m.item_id = i.id) OR EXISTS ( SELECT 1 FROM supply_claim_line l INNER JOIN supply_claim_order o ON o.id = l.order_id WHERE l.item_id = i.id AND IFNULL(o.deleted, 0) = 0 AND o.status = 'FULFILLED' AND IFNULL(l.fulfilled_qty, 0) > 0 ) ) ORDER BY i.id DESC
